function renderHeroNews(e,r){var i=window.formatDate(e.published_at);r.innerHTML=`
        <article class="hero-news">
            <div class="hero-news__content">
                <time datetime="${e.published_at}">${i}</time>
                <h2>${window.escapeHtml(e.title)}</h2>
                <p>${window.escapeHtml(e.excerpt||"")}</p>
                <a href="/news/${e.slug}" class="hero-news__link">Подробнее →</a>
            </div>
            <div class="hero-news__image-placeholder">
                ${e.image_url?`<img src="${e.image_url}" alt="${window.escapeHtml(e.title)}" class="cover-image">`:`
                        <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                            <rect x="3" y="3" width="18" height="18" rx="2" ry="2"/>
                            <circle cx="8.5" cy="8.5" r="1.5"/>
                            <polyline points="21 15 16 10 5 21"/>
                        </svg>
                        <span>Изображение</span>
                    `}
            </div>
        </article>
    `}function renderNewsGrid(e,r){for(var i of e){var t=document.createElement("article"),s=(t.className="news-card",window.formatDate(i.published_at));t.innerHTML=`
            <div class="news-card__image-placeholder">
                ${i.image_url?`<img src="${i.image_url}" alt="${window.escapeHtml(i.title)}" class="cover-image">`:`
                        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                            <rect x="3" y="3" width="18" height="18" rx="2" ry="2"/>
                            <circle cx="8.5" cy="8.5" r="1.5"/>
                            <polyline points="21 15 16 10 5 21"/>
                        </svg>
                        <span>Фото</span>
                    `}
            </div>
            <div class="news-card__body">
                <time datetime="${i.published_at}">${s}</time>
                <h3>${window.escapeHtml(i.title)}</h3>
                <a href="/news/${i.slug}" class="news-card__link">Подробнее ›</a>
            </div>
        `,r.appendChild(t)}}document.addEventListener("DOMContentLoaded",async()=>{var e=document.getElementById("hero-news-container"),r=document.getElementById("news-grid-container");if(e&&r)try{var i=await fetch("/api/news");if(!i.ok)throw new Error("Ошибка загрузки новостей");var t=await i.json();e.innerHTML="",r.innerHTML="",t.hero?renderHeroNews(t.hero,e):e.classList.add("hidden"),t.list&&t.list.length?renderNewsGrid(t.list,r):r.innerHTML='<p class="error-message">Новостей пока нет</p>'}catch(e){console.error(e),r.innerHTML='<p class="error-message">Не удалось загрузить новости</p>'}});